-- ============================================================
-- SEED: logos (BYTEA) por edicion del ERP (auth.edicion_erp.logo)
-- Iconos basados en el logo SIGRE (Pegaso). Generados desde
-- assets/imagenes/ediciones/*.png (redimensionados a 600px).
-- Requiere que las ediciones existan (seed/01-carga-inicial-security).
-- Idempotente: re-ejecutable (UPDATE por codigo).
-- ============================================================

SET client_min_messages TO WARNING;

-- MYPE: mype.png (394979 bytes PNG)
UPDATE auth.edicion_erp SET logo = decode('', 'base64') WHERE codigo = 'MYPE';

-- SMALL_BUSINESS: small-business.png (390242 bytes PNG)
UPDATE auth.edicion_erp SET logo = decode('', 'base64') WHERE codigo = 'SMALL_BUSINESS';

-- PROFESSIONAL: professional.png (425218 bytes PNG)
UPDATE auth.edicion_erp SET logo = decode('', 'base64') WHERE codigo = 'PROFESSIONAL';

-- ENTERPRISE: enterprise.png (381115 bytes PNG)
UPDATE auth.edicion_erp SET logo = decode('', 'base64') WHERE codigo = 'ENTERPRISE';
